module accu(
    input clk, input rst_n, input [7:0] data_in, input valid_in,
    output reg valid_out, output reg [9:0] data_out
);
    integer i;
    reg [9:0] temp_data_out;
    reg [3:0] count;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count <= 4'b0;
            valid_out <= 1'b0;
            data_out <= 10'b0;
        end else begin
            if (valid_in) begin
                if (count < 4) begin
                    temp_data_out <= temp_data_out + data_in;
                    count <= count + 1;
                end else begin
                    data_out <= temp_data_out + data_in;
                    valid_out <= 1'b1;
                    count <= 4'b0;
                end
            end else begin
                valid_out <= 1'b0;
            end
        end
    end

    always @(negedge clk) begin
        if (valid_out) begin
            valid_out <= 1'b0;
        end
    end
endmodule
